const results = [];

for (const item of items) {
  try {
    if (!item.json?.content?.parts?.[0]?.text) return [];

    const text = item.json.content.parts[0].text;

    // Bersihkan markdown jika ada
    let clean = text
      .replace(/```json/g, '')
      .replace(/```/g, '')
      .trim();

    // Parse JSON string
    const parsed = JSON.parse(clean);

    // Push semua question ke results
    for (const q of parsed) {
      results.push({ json: q });
    }

  } catch (err) {
    // skip kalau error
    continue;
  }
}

return results;

const errors = [];
let fileSize = $input.first().binary.data.fileSize
let size = String(fileSize).toLowerCase();
let fileSizeInBytes = parseInt(
  size.includes('mb')
    ? parseFloat(size) * 1024 * 1024
    : size.includes('kb')
      ? parseFloat(size) * 1024
      : parseFloat(size)
);

if(fileSizeInBytes >=5242880){
  errors.push("Files cannot be more than 5MB");
}

return [{
  json: {
    isValid: errors.length === 0,
    errors: errors,
    data : $input.first().binary.data,
    fileName : $input.first().binary.data.fileName.split('.').slice(0, -1).join('.').replaceAll(' ', '-')

  }
}];

// Ambil text hasil extract PDF
let text = $json.text || $json.data || "";

const maxLength = 2000;
const chunks = [];

for (let i = 0; i < text.length; i += maxLength) {
  chunks.push(text.slice(i, i + maxLength));
}

return chunks.map(chunk => ({ json: { chunk } }));
